   } else {
       reply.srb_status = err->service_response;
       reply.scsi_status = err->status;
       reply.data_xfer_length = byte_count - le32_to_cpu(err->residual_count);
       reply.sense_data_size = err->sense_response_data_len;
       memcpy(reply.sense_data, err->sense_response_buf, AAC_SENSE_BUFFERSIZE);
